import { Hono } from 'hono';
import { db } from '../db'; // Assuming you have a database setup

const app = new Hono();

app.delete('/team/:teamId/member/:memberId', async (c) => {
  const teamId = c.req.param('teamId');
  const memberId = c.req.param('memberId');

  if (!teamId || !memberId) {
    return c.json({ error: 'Team ID and Member ID are required' }, 400);
  }

  // Check if the member is the owner
  const team = await db.teams.findFirst({
    where: { id: teamId, ownerId: memberId },
  });

  if (team) {
    return c.json({ error: 'Owner cannot be removed' }, 403);
  }

  // Remove the member from the team
  await db.members.deleteMany({
    where: { teamId, userId: memberId },
  });

  // Unassign all tasks assigned to the member in the team
  await db.tasks.updateMany({
    where: { teamId, assigneeId: memberId },
    data: { assigneeId: null },
  });

  return c.json({ message: 'Member removed successfully' }, 200);
});

export default app;

import { defineTable } from 'drizzle-orm';
import { pgTable, text, uuid } from 'drizzle-orm/pg-core';

export const teams = defineTable({
  id: uuid().primaryKey(),
  ownerId: uuid().notNull(),
  name: text().notNull(),
});

export const members = defineTable({
  id: uuid().primaryKey(),
  teamId: uuid().notNull(),
  userId: uuid().notNull(),
});

export const tasks = defineTable({
  id: uuid().primaryKey(),
  teamId: uuid().notNull(),
  assigneeId: uuid().nullable(),
  title: text().notNull(),
});

import { drizzle } from 'drizzle-orm/pg-js';
import { pgClient } from './pgClient'; // Assuming you have a PostgreSQL client setup

export const db = drizzle(pgClient);

